jsonbIncExpr = (col: Column, deltas: Record<string, number>) => {
  const entries = Object.entries(deltas);
  let expr = sql`${col}`;
  for (const [key, delta] of entries) {
    expr = sql`${expr} || ${jsonbIncFragment(col, key, delta)}`;
  }
  return expr;
}

stats(): {
  cacheSize: number;
  tokenIndexSize: number;
  capacity: number;
  utilization: number;
} {
  const cacheStats = cache.stats;
  return {
    cacheSize: cacheStats.size,
    tokenIndexSize: tokenIndex.size,
    capacity: cacheStats.capacity,
    utilization: cacheStats.utilization,
  };
}

function parseKey(key: string): { entityType: string; entityId: string } | null {
  const colonIndex = key.indexOf(':');
  if (colonIndex === -1) return null;
  return {
    entityType: key.substring(0, colonIndex),
    entityId: key.substring(colonIndex + 1),
  };
}

onDispose: (key, value) => {
  // Clean up reverse index when entry expires or is evicted
  const sessionIds = userIndex.get(value.user.id);
  if (sessionIds) {
    sessionIds.delete(key);
    if (sessionIds.size === 0) userIndex.delete(value.user.id);
  }
}

setSessionCache = (sessionId: string, userId: string, entry: SessionCacheEntry): void => {
  // Jitter TTL ±20% (24-36s) to prevent synchronized expiry under load
  const jitteredTtl = Math.round(30_000 * (0.8 + Math.random() * 0.4));
  sessionCache.set(sessionId, entry, jitteredTtl);

  // Register in reverse index
  let sessionIds = userIndex.get(userId);
  if (!sessionIds) {
    sessionIds = new Set();
    userIndex.set(userId, sessionIds);
  }
  sessionIds.add(sessionId);
}

sysAdminCheck: MiddlewareHandler = async (ctx, next) => {
  const user = ctx.var.user;
  const isSystemAdmin = ctx.var.isSystemAdmin;

  if (!isSystemAdmin) {
    const ip = getIp(ctx) ?? 'unknown';
    sendAccountSecurityEmail(ctx, { email: appConfig.securityEmail, name: 'Security' }, 'sysadmin-fail', {
      ip,
      route: ctx.req.path,
      timestamp: new Date().toISOString(),
    });
    throw new AppError(403, 'no_sysadmin', 'warn', { meta: { user: user.id } });
  }

  await next();
}

tokenLimiter = (tokenType: string): MiddlewareHandler<Env> =>
  rateLimiter('failseries', `token_${tokenType}`, ['ip'], {
    functionName: 'tokenLimiter',
    name: 'token',
    description: 'Blocks IP for 30 min after 10 consecutive token failures',
  })

extractBase = (ctx: LogContext) => {
  if (!ctx?.var) return {};
  const { tenantId, userId, organizationId, requestId } = ctx.var;
  return {
    ...(tenantId && { tenantId }),
    ...(userId && { userId }),
    ...(organizationId && { organizationId }),
    ...(requestId && { requestId }),
  };
}

reject = (rejectionState: RejectionState, id: string, reason: string): RejectionState => ({
  rejectedIds: [...rejectionState.rejectedIds, id],
  rejectionReasons: {
    ...rejectionState.rejectionReasons,
    [reason]: [...(rejectionState.rejectionReasons[reason] ?? []), id],
  },
})

rejectMany = (rejectionState: RejectionState, ids: string[], reason: string): RejectionState => ({
  rejectedIds: [...rejectionState.rejectedIds, ...ids],
  rejectionReasons: {
    ...rejectionState.rejectionReasons,
    [reason]: [...(rejectionState.rejectionReasons[reason] ?? []), ...ids],
  },
})

function seqCursorFilters(seqColumn: Column, raw: string | undefined): SQL[] {
  const cursor = parseSeqCursor(raw);
  const filters: SQL[] = [];
  if (cursor?.gte !== undefined) filters.push(gte(seqColumn, cursor.gte));
  if (cursor?.lte !== undefined) filters.push(lte(seqColumn, cursor.lte));
  return filters;
}

isSystemAccessAllowed = (ctx: Context): boolean => {
  const config = env.SYSTEM_ADMIN_IP_ALLOWLIST;
  if (config === 'none') return false;
  if (config === '*') return true;
  const ip = getIp(ctx);
  return !!ip && config.split(',').includes(ip);
}

function toQueryParams(params: { [key: string]: any }): string {
  const elements = Object.keys(params)

  elements.forEach((element) => {
    if (params[element] === undefined) {
      delete params[element]
    }
  })

  return new URLSearchParams(params).toString()
}

function createOpenApiDefinition(
  securitySchemes: Record<string, OpenAPIV3.SecuritySchemeObject | OpenAPIV3_1.SecuritySchemeObject>,
): OpenAPIV3_1.Document {
  return {
    openapi: '3.1.1',
    info: { title: 'Test API', version: '1.0.0' },
    components: { securitySchemes },
  }
}

function findPreferredResponseKey(responses?: string[]) {
  return (
    // Regular status codes
    ['default', '200', '201', '204', '404', '500'].find((key) => responses?.includes(key) ?? false) ??
    // Lowest status code
    responses?.sort()[0] ??
    undefined
  )
}

async function getActivitiesFromTaskId(taskId: string) {
  const activities = await db.query.activityTable.findMany({
    where: eq(activityTable.taskId, taskId),
    orderBy: [desc(activityTable.createdAt)],
  });

  activities.forEach((x) => {
    if (x.content) {
      x.content = x.content.replace(/\n+/g, "\n");
    }
  });

  return activities;
}

function maskWebhookUrl(value: string): string {
  try {
    const url = new URL(value);
    const parts = url.pathname.split("/").filter(Boolean);
    const last = parts[parts.length - 1] ?? "";
    const maskedLast =
      last.length > 8 ? `${last.slice(0, 4)}…${last.slice(-4)}` : "••••";
    return `${url.origin}/${parts.slice(0, -1).join("/")}/${maskedLast}`;
  } catch {
    return "Configured";
  }
}

function checkPermissions(
  permissions: Record<string, string> | undefined,
  required: string[],
): boolean {
  if (!permissions) return false;

  return required.every((perm) => {
    const permissionLevel = permissions[perm];
    return permissionLevel === "write" || permissionLevel === "admin";
  });
}

function getMissingPermissions(
  permissions: Record<string, string> | undefined,
  required: string[],
): string[] {
  if (!permissions) return required;

  return required.filter((perm) => {
    const permissionLevel = permissions[perm];
    return permissionLevel !== "write" && permissionLevel !== "admin";
  });
}

function getLabel(id: string) {
  const label = db.query.labelTable.findFirst({
    where: (label, { eq }) => eq(label.id, id),
  });

  if (!label) {
    throw new HTTPException(404, {
      message: "Label not found",
    });
  }

  return label;
}

async function validateBearerToken(
  req: Request,
): Promise<{ userId: string; token: string } | null> {
  const authHeader = req.headers.get("authorization");
  if (!authHeader) return null;
  const match = authHeader.match(/^Bearer\s+(\S+)$/i);
  if (!match?.[1]) return null;
  const token = match[1];

  const headers = new Headers();
  headers.set("authorization", `Bearer ${token}`);
  const session = await auth.api.getSession({ headers });

  if (!session?.user?.id) return null;
  return { userId: session.user.id, token };
}

function maskBotToken(value: string): string {
  const [prefix, suffix = ""] = value.split(":", 2);
  if (!suffix) {
    return "Configured";
  }

  const maskedSuffix =
    suffix.length > 8 ? `${suffix.slice(0, 4)}…${suffix.slice(-4)}` : "••••";
  return `${prefix}:${maskedSuffix}`;
}

function builtInRoleStatements(
  role: string,
): Record<string, readonly string[]> | null {
  if (role in builtInRoles) {
    return builtInRoles[role as BuiltInRoleName].statements as Record<
      string,
      readonly string[]
    >;
  }
  return null;
}

async function readJsonObjectBody(
  c: Context,
): Promise<Record<string, unknown>> {
  const raw = (await c.req.json().catch(() => ({}))) || {};
  if (typeof raw !== "object" || raw === null || Array.isArray(raw)) {
    return {};
  }
  return raw as Record<string, unknown>;
}

async function getWorkspaceMembers(workspaceId: string) {
  const members = await db
    .select({
      id: userTable.id,
      name: userTable.name,
      email: userTable.email,
      image: userTable.image,
      role: workspaceUserTable.role,
    })
    .from(workspaceUserTable)
    .innerJoin(userTable, eq(workspaceUserTable.userId, userTable.id))
    .where(eq(workspaceUserTable.workspaceId, workspaceId));

  return members;
}

function addConnection(
  projectId: string,
  ws: WSContext,
  userId: string,
  initiatorId: string,
) {
  if (!projectConnections.has(projectId)) {
    projectConnections.set(projectId, new Set());
  }
  const conn: ProjectConnection = { ws, userId, initiatorId };
  projectConnections.get(projectId)?.add(conn);
  return conn;
}

function removeConnection(projectId: string, conn: ProjectConnection) {
  const connections = projectConnections.get(projectId);
  if (connections) {
    connections.delete(conn);
    if (connections.size === 0) {
      projectConnections.delete(projectId);
    }
  }
}

function pinoLogger() {
  return ((c, next) => logger({
    pino: pino({
      level: c.env.LOG_LEVEL || "info",
    }, c.env.NODE_ENV === "production" ? undefined : pretty()),
    http: {
      reqId: () => randomUUID(),
    },
  })(c as unknown as Context<Env>, next)) satisfies MiddlewareHandler<AppBindings>;
}
